"use client";

import { useState, useEffect, useRef, useCallback, type FormEvent } from "react";

interface BrandPanel {
  id: string;
  name: string;
  logoText: string;
  href: string;
  image: string;
  video: string;
  isYouTube?: boolean;
  subtitle: string;
  description: string;
}

const brands: BrandPanel[] = [
  {
    id: "connect",
    name: "Connect",
    logoText: "CONNECT",
    href: "#",
    image:
      "https://jlr.scene7.com/is/image/jlr/DX_INTRO_STILL_L460?qlt=85&wid=1920&fmt=webp",
    video: "/Connect%20Bg%20Video.mov",
    isYouTube: false,
    subtitle: "Build your Plat3s profile and bring your garage to life.",
    description:
      "Connect your vehicles, share your drives, and link up with drivers who move like you.",
  },
  {
    id: "save",
    name: "Save",
    logoText: "SAVE",
    href: "#",
    image:
      "https://jlr.scene7.com/is/image/jlr/DX_INTRO_STILL_L663?qlt=85&wid=1920&fmt=webp",
    video: "/Save%20_Bg%20Video.mov",
    isYouTube: false,
    subtitle: "Save while you drive.",
    description:
      "Unlock exclusive deals, earn rewards, and keep your vehicle records dialed\u2014automatically.",
  },
  {
    id: "discover",
    name: "Discover",
    logoText: "DISCOVER",
    href: "#",
    image:
      "https://jlr.scene7.com/is/image/jlr/DX_INTRO_STILL_L462?qlt=85&wid=1920&fmt=webp",
    video: "/DiscoverBgVideo.mp4",
    isYouTube: false,
    subtitle: "Discover what\u2019s next.",
    description:
      "Get early access to Plat3s\u2014enter your email and phone to be first when we go live.",
  },
];

const AUTO_ROTATE_MS = 5000;

function VideoBackground({
  brand,
  shouldLoad,
}: {
  brand: BrandPanel;
  shouldLoad: boolean;
}) {
  if (!shouldLoad) return null;

  if (brand.isYouTube) {
    return (
      <div className="absolute inset-0 overflow-hidden">
        <iframe
          src={`https://www.youtube.com/embed/${brand.video}?autoplay=1&mute=1&loop=1&playlist=${brand.video}&controls=0&showinfo=0&rel=0&modestbranding=1&playsinline=1`}
          className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300%] h-[300%] pointer-events-none"
          allow="autoplay; encrypted-media"
          loading="lazy"
          style={{ border: 0 }}
        />
      </div>
    );
  }

  return (
    <video
      className="absolute inset-0 w-full h-full object-cover"
      autoPlay
      muted
      loop
      playsInline
      preload="auto"
    >
      <source src={brand.video} type="video/mp4" />
      <source src={brand.video} type="video/quicktime" />
    </video>
  );
}

function SignupForm({ compact = false }: { compact?: boolean }) {
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    // HubSpot integration placeholder — POST to HubSpot Forms API
    // https://api.hsforms.com/submissions/v3/integration/submit/:portalId/:formGuid
    console.log("Signup:", { email, phone });
    setSubmitted(true);
    setEmail("");
    setPhone("");
    setTimeout(() => setSubmitted(false), 3000);
  };

  if (submitted) {
    return (
      <p className="text-white/80 text-sm tracking-wide animate-fadeIn">
        You&apos;re on the list. We&apos;ll be in touch.
      </p>
    );
  }

  return (
    <form
      onSubmit={handleSubmit}
      onClick={(e) => e.preventDefault()}
      className={`flex flex-col gap-3 ${compact ? "w-full max-w-xs" : "w-full max-w-sm"}`}
    >
      <input
        type="email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        placeholder="Email address"
        required
        className="bg-white/10 backdrop-blur-sm border border-white/20 px-4 py-2.5 text-sm text-white placeholder:text-white/40 focus:outline-none focus:border-white/50 transition-colors rounded-none"
      />
      <input
        type="tel"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
        placeholder="Phone number"
        required
        className="bg-white/10 backdrop-blur-sm border border-white/20 px-4 py-2.5 text-sm text-white placeholder:text-white/40 focus:outline-none focus:border-white/50 transition-colors rounded-none"
      />
      <button
        type="submit"
        className="bg-white text-[#0c121c] text-xs tracking-[0.2em] uppercase font-semibold px-6 py-2.5 hover:bg-white/90 transition-colors"
      >
        {compact ? "Get Notified" : "Get Early Access"}
      </button>
    </form>
  );
}

export default function HeroBrands() {
  const [hoveredId, setHoveredId] = useState<string | null>(null);
  const [activeIndex, setActiveIndex] = useState(0);
  const [direction, setDirection] = useState<"next" | "prev">("next");
  const [isAnimating, setIsAnimating] = useState(false);
  const [mounted, setMounted] = useState(false);
  const [mobileFormOpen, setMobileFormOpen] = useState(false);
  const touchStartX = useRef(0);
  const touchEndX = useRef(0);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => setMounted(true), []);

  const goTo = useCallback(
    (index: number, dir: "next" | "prev") => {
      if (isAnimating) return;
      setDirection(dir);
      setIsAnimating(true);
      setActiveIndex(index);
      setMobileFormOpen(false);
      setTimeout(() => setIsAnimating(false), 700);
    },
    [isAnimating]
  );

  const goNext = useCallback(() => {
    goTo((activeIndex + 1) % brands.length, "next");
  }, [activeIndex, goTo]);

  const goPrev = useCallback(() => {
    goTo((activeIndex - 1 + brands.length) % brands.length, "prev");
  }, [activeIndex, goTo]);

  useEffect(() => {
    if (mobileFormOpen) return; // pause auto-rotate when form is open
    timerRef.current = setTimeout(goNext, AUTO_ROTATE_MS);
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [activeIndex, goNext, mobileFormOpen]);

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    touchEndX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = () => {
    const delta = touchStartX.current - touchEndX.current;
    if (Math.abs(delta) > 50) {
      if (delta > 0) goNext();
      else goPrev();
    }
  };

  return (
    <section className="relative w-full min-h-screen">
      {/* ===== MOBILE CAROUSEL (< lg) ===== */}
      <div
        className="lg:hidden relative w-full h-screen overflow-hidden"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
      >
        {brands.map((brand, i) => {
          const isCurrent = i === activeIndex;
          const isDiscover = brand.id === "discover";

          let transformClass = "";
          if (isCurrent && mounted) {
            transformClass =
              direction === "next"
                ? "animate-slideInRight"
                : "animate-slideInLeft";
          }

          return (
            <div
              key={brand.id}
              className={`absolute inset-0 flex items-center justify-center transition-opacity duration-700 ${
                isCurrent
                  ? `opacity-100 z-10 ${transformClass}`
                  : "opacity-0 z-0"
              }`}
            >
              <div
                className="absolute inset-0 bg-cover bg-center"
                style={{ backgroundImage: `url(${brand.image})` }}
              />
              <VideoBackground
                brand={brand}
                shouldLoad={mounted && (isCurrent || Math.abs(i - activeIndex) <= 1)}
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/30 to-black/40" />

              {/* Content */}
              <div className="relative z-10 flex flex-col items-center text-center px-10 max-w-lg">
                <h2
                  className="text-white text-5xl tracking-[0.35em] uppercase"
                  style={{ fontFamily: "LandRoverWeb-Bold, sans-serif" }}
                >
                  {brand.logoText}
                </h2>
                <span
                  className={`block h-px bg-white/60 transition-all duration-700 ease-out mt-6 ${
                    isCurrent ? "w-16 opacity-100" : "w-0 opacity-0"
                  }`}
                />
                {/* Subtext */}
                <p className="text-white text-lg font-medium leading-snug mt-8">
                  {brand.subtitle}
                </p>
                <p className="text-white/60 text-base leading-7 mt-4">
                  {brand.description}
                </p>

                {/* Discover: Get Notified CTA + form */}
                {isDiscover && !mobileFormOpen && (
                  <button
                    onClick={() => setMobileFormOpen(true)}
                    className="mt-4 bg-white text-[#0c121c] text-xs tracking-[0.2em] uppercase font-semibold px-8 py-3 hover:bg-white/90 transition-colors"
                  >
                    Get Notified
                  </button>
                )}
                {isDiscover && mobileFormOpen && (
                  <div className="mt-4 w-full flex justify-center">
                    <SignupForm compact />
                  </div>
                )}
              </div>
            </div>
          );
        })}

        {/* Dot indicators */}
        <div className="absolute bottom-10 left-0 right-0 z-20 flex justify-center gap-3">
          {brands.map((_, i) => (
            <button
              key={i}
              aria-label={`Go to slide ${i + 1}`}
              onClick={() => goTo(i, i > activeIndex ? "next" : "prev")}
              className={`h-[2px] rounded-full transition-all duration-500 ${
                i === activeIndex
                  ? "w-8 bg-white"
                  : "w-4 bg-white/30 hover:bg-white/50"
              }`}
            />
          ))}
        </div>
      </div>

      {/* ===== DESKTOP COLUMNS (lg+) ===== */}
      <div className="hidden lg:flex w-full min-h-screen">
        {brands.map((brand) => {
          const isHovered = hoveredId === brand.id;
          const isOtherHovered = hoveredId !== null && hoveredId !== brand.id;
          const isDiscover = brand.id === "discover";

          return (
            <div
              key={brand.id}
              className={`relative flex-1 flex flex-col items-center justify-center overflow-hidden transition-all duration-700 ease-in-out min-h-screen cursor-pointer ${
                isHovered
                  ? "flex-[1.5]"
                  : isOtherHovered
                  ? "flex-[0.75]"
                  : "flex-1"
              }`}
              onMouseEnter={() => setHoveredId(brand.id)}
              onMouseLeave={() => setHoveredId(null)}
            >
              <div
                className="absolute inset-0 bg-cover bg-center transition-transform duration-700"
                style={{ backgroundImage: `url(${brand.image})` }}
              />
              <VideoBackground brand={brand} shouldLoad={mounted} />

              {/* Gradient overlay — darker on hover for readability */}
              <div
                className={`absolute inset-0 transition-all duration-500 ${
                  isHovered
                    ? "bg-gradient-to-t from-black/70 via-black/40 to-black/30"
                    : "bg-gradient-to-t from-black/50 via-transparent to-black/30"
                }`}
              />

              {/* Content */}
              <div className="relative z-10 flex flex-col items-center justify-center text-center px-10 max-w-md">
                <h2
                  className="text-white text-5xl tracking-[0.3em] uppercase"
                  style={{ fontFamily: "LandRoverWeb-Bold, sans-serif" }}
                >
                  {brand.logoText}
                </h2>

                {/* Subtext — revealed on hover */}
                <div
                  className={`overflow-hidden transition-all duration-500 ease-out ${
                    isHovered
                      ? "max-h-[500px] opacity-100 mt-10"
                      : "max-h-0 opacity-0 mt-0"
                  }`}
                >
                  <p className="text-white text-lg font-medium leading-snug mb-5">
                    {brand.subtitle}
                  </p>
                  <p className="text-white/60 text-base leading-7">
                    {brand.description}
                  </p>

                  {/* Discover form */}
                  {isDiscover && (
                    <div className="mt-5">
                      <SignupForm />
                    </div>
                  )}
                </div>
              </div>

              {/* Divider lines between panels */}
              <div className="absolute right-0 top-[15%] bottom-[15%] w-px bg-white/20" />
            </div>
          );
        })}
      </div>
    </section>
  );
}
